<template>
  <v-card class="pa-4 custom-card-height" outlined>
    <!-- Centered Title and Dropdown -->
    <v-row align="center" justify="center" class="mb-2">
      <v-col class="d-flex justify-center align-center">
        <v-text variant="h5" class="custom-title">Login Trends</v-text>
      </v-col>
      <v-col cols="auto" class="d-flex align-center">
        <!-- Filter Dropdown -->
        <v-select
          v-model="selectedFilter"
          :items="filterOptions"
          item-title="text"
          item-value="value"
          label="Select Interval"
          class="custom-select"
          dense
          variant="outlined"
          style="max-width: 150px;"
          :menu-props="{ maxWidth: '150px' }"
        ></v-select>
      </v-col>
    </v-row>

    <!-- ApexChart Component -->
    <div class="chart-container">
      <apexchart
        type="line"
        height="100%"
        :options="chartOptions"
        :series="chartSeries"
      />
    </div>
  </v-card>
</template>



<script>
import { ref, watch, onMounted, computed } from 'vue';
import VueApexCharts from 'vue3-apexcharts';

export default {
  components: {
    apexchart: VueApexCharts,
  },
  props: {
    loginsData: {
      type: Array,
      required: true,
    },
  },
  setup(props) {
    const selectedFilter = ref('day'); // Default filter to 'day'
    const filterOptions = [
      { text: 'Day', value: 'day' },
      { text: 'Week', value: 'week' },
      { text: 'Month', value: 'month' },
    ];

    const chartOptions = ref({});
    const chartSeries = ref([]);

    // Aggregate data based on selected filter
    const filteredData = computed(() => {
      let data = [...props.loginsData];

      if (selectedFilter.value === 'week') {
        data = aggregateDataByWeek(data);
      } else if (selectedFilter.value === 'month') {
        data = aggregateDataByMonth(data);
      }

      return data;
    });

    const updateChart = (data) => {
      const labels = data.map(item => item.date);
      const counts = data.map(item => item.count);

      // Calculate thresholds for the top 10% and bottom 10%
      const sortedCounts = [...counts].sort((a, b) => a - b);
      const topThreshold = sortedCounts[Math.floor(0.9 * sortedCounts.length)];
      const bottomThreshold = sortedCounts[Math.floor(0.1 * sortedCounts.length)];

      // Create a custom color array where high points are highlighted in red, low points in blue, and others in a standard color
      const colors = counts.map(count => {
        if (count >= topThreshold) {
          return '#E91E63'; // Color for peak points (e.g., red)
        } else if (count <= bottomThreshold) {
          return '#2196F3'; // Color for valley points (e.g., blue)
        } else {
          return '#4CAF50'; // Standard color for regular points (e.g., green)
        }
      });

      chartOptions.value = {
        chart: {
          type: 'line',
          height: 350,
          toolbar: {
            show: false,
          },
        },
        xaxis: {
          categories: labels,
          title: {
            text: 'Date',
          },
        },
        yaxis: {
          title: {
            text: 'Number of Logins',
          },
        },
        stroke: {
          curve: 'smooth',
          width: 2,
          colors: colors, // Apply the custom color array
        },
        dataLabels: {
          enabled: false,
        },
        markers: {
          size: 5,
          colors: colors, // Ensure markers follow the color scheme
        },
        tooltip: {
          x: {
            format: 'dd/MM/yy',
          },
          y: {
            formatter: val => `${val} logins`,
          },
        },
      };

      chartSeries.value = [
        {
          name: 'Logins',
          data: counts,
        },
      ];
    };


    // Watch for changes in filteredData to update the chart
    watch(filteredData, (newData) => {
      updateChart(newData);
    }, { immediate: true });

    // Ensure chart is created after the component is mounted
    onMounted(() => {
      if (filteredData.value.length > 0) {
        updateChart(filteredData.value);
      }
    });

    // Aggregate data by week
    const aggregateDataByWeek = (data) => {
      const weeklyData = {};

      data.forEach(item => {
        const date = new Date(item.date);
        const weekNumber = getWeekNumber(date);
        const weekKey = `${date.getFullYear()}-W${weekNumber}`;
        weeklyData[weekKey] = (weeklyData[weekKey] || 0) + item.count;
      });

      return Object.entries(weeklyData).map(([week, count]) => ({
        date: week,
        count,
      }));
    };

    // Function to get ISO week number
    const getWeekNumber = (date) => {
      const firstDayOfYear = new Date(date.getFullYear(), 0, 1);
      const pastDaysOfYear = (date - firstDayOfYear) / 86400000;
      return Math.ceil((pastDaysOfYear + firstDayOfYear.getDay() + 1) / 7);
    };

    // Aggregate data by month
    const aggregateDataByMonth = (data) => {
      const monthlyData = {};

      data.forEach(item => {
        const date = new Date(item.date);
        const monthKey = `${date.getFullYear()}-${(date.getMonth() + 1)
          .toString()
          .padStart(2, '0')}`;
        monthlyData[monthKey] = (monthlyData[monthKey] || 0) + item.count;
      });

      return Object.entries(monthlyData).map(([month, count]) => ({
        date: month,
        count,
      }));
    };

    return {
      selectedFilter,
      filterOptions,
      chartOptions,
      chartSeries,
    };
  },
};
</script>

<style scoped>
.custom-card-height {
  height: 460px; /* Set a fixed height for the card */
  display: flex;
  flex-direction: column;
}

.chart-container {
  flex-grow: 1; /* Make the chart container take up the remaining space */
}

.custom-select {
  margin-top: 12px; /* Add a small top margin to move the dropdown down */
}

.custom-select .v-input__control {
  height: 30px;
  padding-top: 8px; /* Increased padding-top */
  padding-bottom: 4px;
}

.custom-select .v-select__selections {
  font-size: 14px;
}

.custom-title {
  font-size: 24px;
  font-weight: bold;
  margin-bottom: 8px; /* Adjust margin for title */
}
</style>

